function solve(nums: number[], k: number): number {
    let prefixMod = 0;
    const modMap = new Map<number, number>();
    modMap.set(0, -1);
    let minSum = 0;
    const n = nums.length;
    const dp = new Array(n + 1).fill(0);

    for (let i = 0; i < n; i++) {
        prefixMod = (prefixMod + nums[i]) % k;
        if (modMap.has(prefixMod)) {
            const prevIndex = modMap.get(prefixMod)!;
            dp[i + 1] = Math.max(dp[i], dp[prevIndex + 1] + nums[i]);
        } else {
            dp[i + 1] = dp[i];
        }
        modMap.set(prefixMod, i);
    }

    const totalSum = nums.reduce((a, b) => a + b, 0);
    minSum = totalSum - dp[n];
    return minSum;
}
